create policy "Authenticated users can read active skill categories"
on "public"."skill_categories"
as permissive
for select
to authenticated
using (is_active = true);

create policy "Authenticated users can read active skills"
on "public"."skills"
as permissive
for select
to authenticated
using (
  is_active = true
  and exists (
    select 1
    from public.skill_categories sc
    where sc.id = skills.category_id
      and sc.is_active = true
  )
);

create policy "Users can read reusable and own media"
on "public"."media"
as permissive
for select
to authenticated
using (
  profile_id is null
  or exists (
    select 1
    from public.profiles p
    where p.id = media.profile_id
      and p.auth_user_id = auth.uid()
  )
  or exists (
    select 1
    from public.member_skill_media msm
    join public.member_skill_progress msp on msp.id = msm.progress_id
    join public.profiles p on p.id = msp.profile_id
    where msm.media_id = media.id
      and p.auth_user_id = auth.uid()
  )
);

create policy "Users can create own media"
on "public"."media"
as permissive
for insert
to authenticated
with check (
  exists (
    select 1
    from public.profiles p
    where p.id = media.profile_id
      and p.auth_user_id = auth.uid()
  )
);

