create policy "Users can read relevant comments"
on "public"."comments"
as permissive
for select
to authenticated
using (
  exists (
    select 1
    from public.profiles p
    where p.id = comments.profile_id
      and p.auth_user_id = auth.uid()
  )
  or exists (
    select 1
    from public.member_skill_comments msc
    join public.member_skill_progress msp on msp.id = msc.progress_id
    join public.profiles p on p.id = msp.profile_id
    where msc.comment_id = comments.id
      and p.auth_user_id = auth.uid()
  )
);

