create policy "Users can create own skill comment links"
on "public"."member_skill_comments"
as permissive
for insert
to authenticated
with check (
  exists (
    select 1
    from public.member_skill_progress msp
    join public.profiles owner_profile on owner_profile.id = msp.profile_id
    join public.comments c on c.id = member_skill_comments.comment_id
    join public.profiles commenter_profile on commenter_profile.id = c.profile_id
    where msp.id = member_skill_comments.progress_id
      and owner_profile.auth_user_id = auth.uid()
      and commenter_profile.auth_user_id = auth.uid()
  )
);

