comment on table public.media is 'Reusable photo/video records for tutorials, player uploads, and future app features.';
comment on column public.media.type is '0 = image, 1 = video.';
comment on column public.media.storage_path is 'Supabase Storage path or external media location.';
comment on column public.comments.content is 'Rich comment payload. Keep body populated for plain-text preview/search when possible.';
comment on table public.skill_categories is 'Configurable table tennis skill ladder categories such as Serve, Forehand, Backhand, and Mental Game.';
comment on table public.skills is 'Individual skill ladder items under each category.';
comment on table public.member_skill_progress is 'One progress row per profile and skill.';
comment on column public.member_skill_progress.current_level is '0 Not Started, 1 Learning, 2 Practice Ready, 3 Match Ready, 4 Reliable Under Pressure, 5 Advanced / Weapon.';
comment on table public.member_skill_media is 'Links member practice media to a skill progress row.';
comment on table public.member_skill_comments is 'Links notes and coach/player comments to a member skill progress row, optionally for a specific media item.';
